import matplotlib.pyplot as plt
import matplotlib.gridspec as gridspec
import numpy as np

# --- THEME & COLORS ---
color_bg = "#121926"     # Dark Navy
color_heads = "#3b82f6"  # Blue
color_tails = "#059669"  # Green
color_pink = "#f472b6"   # Probability Highlight
color_grid = "#2d3748"

plt.rcParams.update({
    "figure.facecolor": color_bg, 
    "axes.facecolor": color_bg,
    "axes.edgecolor": "#444b5a", 
    "axes.labelcolor": "#ffffff",
    "xtick.color": "#aeb4c1", 
    "ytick.color": "#aeb4c1",
    "grid.color": color_grid, 
    "text.color": "#ffffff",
    "font.size": 9
})

def apply_table_style(tbl):
    for (r, c), cell in tbl.get_celld().items():
        cell.set_edgecolor("#444b5a")
        cell.set_facecolor(color_bg)
        if r == 0: cell.set_facecolor("#1f2937") 
        if c == 2 and r > 0: cell.get_text().set_color(color_pink) 
        if r == 1 and c < 2: cell.get_text().set_color(color_heads) 
        if r == 2 and c < 2: cell.get_text().set_color(color_tails)

