all_h_global, all_t_global = [], []
coins = list(raw_data.keys())

# --- INDIVIDUAL COIN POP-UPS ---
for coin in coins:
    data = raw_data[coin]
    h_list = [item for sublist in data["heads_groups"] for item in sublist]
    t_list = [item for sublist in data["tails_groups"] for item in sublist]
    
    all_h_global.extend(h_list)
    all_t_global.extend(t_list)
    
    h_p, t_p = np.cumsum(h_list), np.cumsum(t_list)
    total = len(h_list)

    fig, ax = plt.subplots(figsize=(10, 8))
    ax.plot(h_p, color=color_heads, linewidth=2.5, label=f"H: {h_p[-1]} ({(h_p[-1]/total)*100:.1f}%)")
    ax.plot(t_p, color=color_tails, linewidth=2.5, label=f"T: {t_p[-1]} ({(t_p[-1]/total)*100:.1f}%)")

    ax.set_title(f"Coin Class: {coin}", fontweight='bold', fontsize=12, pad=15)
    ax.legend(loc='upper left', facecolor='#1a222f', edgecolor=color_grid)
    ax.set_xlabel("Toss #")
    ax.grid(True, alpha=0.2)
    
    t_data = [["Outcome", "Count", "Probability"], 
              ["Heads (H)", f"{h_p[-1]}", f"{(h_p[-1]/total)*100:.1f}%"], 
              ["Tails (T)", f"{t_p[-1]}", f"{(t_p[-1]/total)*100:.1f}%"]]
    tbl = ax.table(cellText=t_data, loc='bottom', bbox=[0.15, -0.45, 0.7, 0.3], cellLoc='center')
    apply_table_style(tbl)
    plt.subplots_adjust(bottom=0.35)
    plt.show()

# --- THE 8-GRAPH GRID COMPARISON ---
if coins:
    fig_grid = plt.figure(figsize=(24, 15)) 
    gs = gridspec.GridSpec(2, 4, hspace=0.7, wspace=0.3) # Increased spacing

    for i, coin in enumerate(coins):
        ax = fig_grid.add_subplot(gs[i//4, i%4])
        data = raw_data[coin]
        h_vals = [item for sublist in data["heads_groups"] for item in sublist]
        t_vals = [item for sublist in data["tails_groups"] for item in sublist]
        h_p, t_p = np.cumsum(h_vals), np.cumsum(t_vals)
        total = len(h_vals)

        ax.plot(h_p, color=color_heads, linewidth=2, label=f"H: {h_p[-1]}") 
        ax.plot(t_p, color=color_tails, linewidth=2, label=f"T: {t_p[-1]}")
        
        ax.set_title(f"Class {coin}", fontsize=14, fontweight='bold', pad=35) 
        ax.legend(fontsize=8, loc='upper left', facecolor='#1a222f', framealpha=0.8)
        ax.grid(True, alpha=0.1)

    fig_grid.suptitle("All Coin Classes - Grid Comparison", fontsize=22, fontweight='bold', y=0.98)
    plt.show()